sql:
SELECT email 
FROM users 
WHERE user_id IN (SELECT individual_id FROM demographics);

external_knowledge:
- "mature folks" refers to individuals older than 50 years old;
- "family sizes" refers to the number of children the individuals have;
- "health habits" refer to whether they are smokers or not;
- "where they live" is specified as the "southwest" region.

sql:
SELECT AVG(bmi) AS average_bmi
FROM individuals
WHERE age > 50 AND bmi > (SELECT AVG(bmi) FROM individuals);

external_knowledge:
- 'middle-aged' refers to individuals over the age of 30;
- 'recent edits' means the access logs show an 'edit' type on or after January 1, 2023;
- 'above a certain threshold' refers to an average health metric value greater than 33.77.

sql:
SELECT age, smoker
FROM individuals
ORDER BY age ASC;

SELECT AVG(bmi) AS Average_BMI
FROM individuals
WHERE occupation IN ('Doctor', 'Engineer', 'Professor');
